INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1420, 193597, 5, 106, '南京到厦门', '从南京回到厦门，30多小时，旅途漫漫。做硬座的车，又带着3个好大好大的包（我拣了很多垃圾回家），感觉上挤死了。幸好还没到春运，不然可更惨，更血腥、更恐怖了。装衣服的包，丢架子上去；装食物的包，塞座位下去；最最最重的书包，像以前上课一样，抱好咯。然后，不知道做什么事好了。左边一大爷+一大嫂，对面是三个女生。拿不出胆子和他们讲话，我就坐在那里乖乖的、乖乖的，翻开了书，1、2、3，哎哟，实在是无趣得很，算了，就在那里听他们讲话好了~~大嫂AM6：00下车，老爷子PM10：00下车，三个女生是南京气象学院的，一个漳州的、一个南京的、一个无锡的（可欣赏程度以几何数级递增……），准备到厦大住几宿，看看我们美丽的厦门。坐着听他们聊天，聊啊聊的，想睡觉，可是不行的啊。不过挨过了夜幕，大嫂下了车，而且姑娘们的朋友招呼她们去卧铺休息，我的手脚才有了舒展一下的权利。南京姑娘留了下来，坐在那里，吃了几片面包，和大爷扯了几句，小心翼翼地问我会不会玩牌，“会”，拉上我一起玩牌了。打着牌，聊起了天。她问着，我答着，讲起了厦门，讲到了我自己，还其他好多好多……被问着、问着，我就莫名其妙地给感动了，至少自己这样觉得。玩牌玩得累了，她休息了一会儿，我看着她，忽然就想起了某个人。突然觉得自己很喜欢她这样的人，很喜欢她这样的朋友，只是还不知道人家有没有当我朋友来着呢。又继续地打牌、聊天，到漳州和无锡回来了，到夜幕再次降临，到老大爷下车，熬着剩下的时间，一点一点……清晨6：00回到了厦门，我老觉得自己有点舍不得和他们分开了。无锡姑娘很漂亮，可惜没给她照张相。
<br>下了火车，回家洗了个澡，竟不觉得困，跑到学校看望了复读的同学后，又去厦大那里闲逛，希望能够遇见他们吧，可惜不如愿。也不知道给他们留了的电话，会不会给我打呢……', '从南京回到厦门，30多小时，旅途漫漫。做硬座的车，又带着3个好大好大的包（我拣了很多垃圾回家），感觉上挤死了。幸好还没到春运，不然可更惨，更血腥、更恐怖了。装衣服的包，丢架子上去；装食物的包，塞座位下去；最最最重的书包，像以前上课一样，抱好咯。然后，不知道做什么事好了。左边一大爷+一大嫂，对面是三个女生。拿不出胆子和他们讲话，我就坐在那里乖乖的、乖乖的，翻开了书，1、2、3，哎哟，实在是无趣得很，算了，就在那里听他们讲话好了~~大嫂AM6：00下车，老爷子PM10：00下车，三个女生是南京气象学院的，一个漳州的、一个南京的、一个无锡的（可欣赏程度以几何数级递增……），准备到厦大住几宿，看看我们美丽的厦门。坐着听他们聊天，聊啊聊的，想睡觉，可是不行的啊。不过挨过了夜幕，大嫂下了车，而且姑娘们的朋友招呼她们去卧铺休息，我的手脚才有了舒展一下的权利。南京姑娘留了下来，坐在那里，吃了几片面包，和大爷扯了几句，小心翼翼地问我会不会玩牌，“会”，拉上我一起玩牌了。打着牌，聊起了天。她问着，我答着，讲起了厦门，讲到了我自己，还其他好多好多……被问着、问着，我就莫名其妙地给感动了，至少自己这样觉得。玩牌玩得累了，她休息了一会儿，我看着她，忽然就想起了某个人。突然觉得自己很喜欢她这样的人，很喜欢她这样的朋友，只是还不知道人家有没有当我朋友来着呢。又继续地打牌、聊天，到漳州和无锡回来了，到夜幕再次降临，到老大爷下车，熬着剩下的时间，一点一点……清晨6：00回到了厦门，我老觉得自己有点舍不得和他们分开了。无锡姑娘很漂亮，可惜没给她照张相。

下了火车，回家洗了个澡，竟不觉得困，跑到学校看望了复读的同学后，又去厦大那里闲逛，希望能够遇见他们吧，可惜不如愿。也不知道给他们留了的电话，会不会给我打呢……', NULL, '2003-01-18 21:47:00', 7, '20030217224649_bbsid_193597_board_5_401db6a09b.html', '20030217224649');
